<template>
  <section class="portal-module board-module">
    <div class="portal-module__head"><div><span class="portal-module__eyebrow">KANBAN</span><h2>{{ project.title }}</h2></div><div class="board-module__head-actions"><q-btn v-if="admin" unelevated no-caps class="portal-module__primary" icon="mdi-plus" label="Nova tarefa" @click="openTask()" /><q-btn v-if="admin" flat no-caps icon="mdi-view-column-outline" label="Colunas" @click="openColumns" /></div></div>
    <div v-if="loading" class="board-module__loading"><q-spinner color="teal-3" size="32px" /> Carregando board...</div>
    <template v-else>
      <div class="board-module__mobile-controls"><q-select v-model="mobileColumn" outlined dense label="Coluna" :options="columnOptions" emit-value map-options /><q-btn v-if="admin" unelevated no-caps class="portal-module__primary" icon="mdi-plus" label="Adicionar task" @click="openTask(null, mobileColumn)" /></div>
      <div class="board-module__columns">
        <section v-for="column in board.columns" :key="column.key" class="board-column" :class="{ 'board-column--mobile-hidden': column.key !== mobileColumn }" @dragover.prevent @drop="dropTask(column.key)">
          <header class="board-column__head"><div><span>{{ String(column.position + 1).padStart(2, '0') }}</span><h3>{{ column.title }}</h3></div><b>{{ tasksFor(column.key).length }}</b></header>
          <div class="board-column__tasks"><article v-for="task in tasksFor(column.key)" :key="task._id" class="board-task" :draggable="admin" @dragstart="draggedTask = task"><div class="board-task__meta"><span>{{ formatDate(task.dueDate) }}</span><q-icon name="mdi-dots-horizontal" /></div><h4>{{ task.title }}</h4><p>{{ preview(task.description) }}</p><div class="board-task__footer"><small>{{ formatDate(task.createdAt) }}</small><span class="board-task__actions"><q-btn v-if="admin" flat round dense icon="mdi-pencil" aria-label="Editar tarefa" @click="openTask(task)" /><q-btn v-if="admin" flat round dense color="negative" icon="mdi-delete-outline" aria-label="Excluir tarefa" @click="removeTask(task)" /><q-btn v-else flat dense no-caps icon="mdi-chat-plus-outline" label="Solicitar ajuste" @click="openRequest(task)" /></span></div></article><span v-if="!tasksFor(column.key).length" class="board-column__empty">Nenhuma tarefa</span></div>
        </section>
      </div>
    </template>

    <ProjectLinkedPanels :project="project" :admin="admin" />

    <q-dialog v-model="taskDialog"><q-card class="portal-module__dialog board-module__dialog"><q-card-section class="portal-module__dialog-head"><div><span class="portal-module__eyebrow">Task</span><h3>{{ taskForm._id ? 'Editar tarefa' : 'Nova tarefa' }}</h3></div><q-btn flat round dense icon="mdi-close" aria-label="Fechar" @click="taskDialog = false" /></q-card-section><q-card-section><q-form @submit.prevent="saveTask"><q-input v-model="taskForm.title" outlined label="Titulo" :rules="[requiredRule]" /><q-input v-model="taskForm.description" outlined type="textarea" autogrow label="Descricao" class="q-mt-sm" /><q-select v-model="taskForm.columnKey" outlined label="Coluna" :options="columnOptions" emit-value map-options class="q-mt-sm" /><div class="board-module__dates"><q-input v-model="taskForm.startDate" outlined type="date" label="Data de inicio" /><q-input v-model="taskForm.dueDate" outlined type="date" label="Data limite" /></div><q-btn unelevated no-caps class="portal-module__primary full-width q-mt-md" type="submit" label="Salvar tarefa" :loading="saving" /></q-form></q-card-section></q-card></q-dialog>

    <q-dialog v-model="columnsDialog"><q-card class="portal-module__dialog board-module__dialog"><q-card-section class="portal-module__dialog-head"><div><span class="portal-module__eyebrow">Board</span><h3>Colunas</h3></div><q-btn flat round dense icon="mdi-close" aria-label="Fechar" @click="columnsDialog = false" /></q-card-section><q-card-section><div v-for="(column, index) in editableColumns" :key="column.key" class="board-module__column-edit"><q-input v-model="column.title" outlined dense label="Titulo" /><q-btn flat round dense color="negative" icon="mdi-delete-outline" aria-label="Remover coluna" :disable="editableColumns.length <= 1" @click="editableColumns.splice(index, 1)" /></div><div class="board-module__column-add"><q-input v-model="newColumnTitle" outlined dense label="Nova coluna" @keyup.enter="addColumn" /><q-btn flat round dense icon="mdi-plus" aria-label="Adicionar coluna" @click="addColumn" /></div><q-btn unelevated no-caps class="portal-module__primary full-width q-mt-md" label="Salvar colunas" :loading="saving" @click="saveColumns" /></q-card-section></q-card></q-dialog>

    <q-dialog v-model="requestDialog"><q-card class="portal-module__dialog board-module__dialog"><q-card-section class="portal-module__dialog-head"><div><span class="portal-module__eyebrow">Suporte</span><h3>Solicitar ajuste</h3></div><q-btn flat round dense icon="mdi-close" aria-label="Fechar" @click="requestDialog = false" /></q-card-section><q-card-section><p class="board-module__request-copy">Descreva o que precisa ser alterado na tarefa <strong>{{ requestTask.title }}</strong>.</p><q-form @submit.prevent="requestChange"><q-input v-model="requestDescription" outlined type="textarea" autogrow label="Descricao do chamado" :rules="[requiredRule]" /><q-btn unelevated no-caps class="portal-module__primary full-width q-mt-md" type="submit" label="Abrir chamado" :loading="saving" /></q-form></q-card-section></q-card></q-dialog>
  </section>
</template>

<script setup>
import { computed, onMounted, ref } from 'vue'
import { useQuasar } from 'quasar'
import { api } from 'boot/axios'
import ProjectLinkedPanels from 'components/ProjectLinkedPanels.vue'

const props = defineProps({ project: { type: Object, required: true }, admin: { type: Boolean, default: false } })
defineEmits(['back'])
const $q = useQuasar(); const token = localStorage.getItem(props.admin ? 'aito_admin_token' : 'aito_user_token'); const headers = { Authorization: `Bearer ${token}` }
const board = ref({ columns: [] }); const tasks = ref([]); const loading = ref(false); const saving = ref(false); const taskDialog = ref(false); const columnsDialog = ref(false); const requestDialog = ref(false); const draggedTask = ref(null); const mobileColumn = ref('backlog'); const editableColumns = ref([]); const newColumnTitle = ref(''); const taskForm = ref(emptyTask()); const requestTask = ref({}); const requestDescription = ref('')
const columnOptions = computed(() => board.value.columns.map((column) => ({ label: column.title, value: column.key })))
function emptyTask () { return { _id: '', title: '', description: '', columnKey: 'backlog', startDate: '', dueDate: '' } }
function requiredRule (value) { return Boolean(String(value || '').trim()) || 'Preencha este campo.' }
function preview (value) { const text = String(value || '').trim(); return text.length > 94 ? `${text.slice(0, 94)}...` : text || 'Sem descricao.' }
function formatDate (value) { return value ? new Date(value).toLocaleDateString('pt-BR') : 'Sem prazo' }
function tasksFor (columnKey) { return tasks.value.filter((task) => task.columnKey === columnKey) }
async function load () { loading.value = true; try { const endpoint = props.admin ? `/admin/projects/${props.project._id}/board` : `/projects/${props.project._id}/board`; const response = await api.get(endpoint, { headers }); board.value = response.data.data.board || { columns: [] }; tasks.value = response.data.data.tasks || []; if (!board.value.columns.some((column) => column.key === mobileColumn.value)) mobileColumn.value = board.value.columns[0]?.key || '' } catch (error) { notifyError(error) } finally { loading.value = false } }
function openTask (task = null, columnKey = null) { taskForm.value = task ? { ...emptyTask(), ...task, columnKey: task.columnKey, startDate: task.startDate ? String(task.startDate).slice(0, 10) : '', dueDate: task.dueDate ? String(task.dueDate).slice(0, 10) : '' } : { ...emptyTask(), columnKey: columnKey || mobileColumn.value || board.value.columns[0]?.key || 'backlog' }; taskDialog.value = true }
async function saveTask () { saving.value = true; try { const endpoint = taskForm.value._id ? `/admin/projects/${props.project._id}/tasks/${taskForm.value._id}` : `/admin/projects/${props.project._id}/tasks`; const response = taskForm.value._id ? await api.put(endpoint, taskForm.value, { headers }) : await api.post(endpoint, taskForm.value, { headers }); if (taskForm.value._id) tasks.value = tasks.value.map((task) => task._id === taskForm.value._id ? response.data.data : task); else tasks.value.push(response.data.data); taskDialog.value = false; $q.notify({ type: 'positive', message: 'Tarefa salva.' }) } catch (error) { notifyError(error) } finally { saving.value = false } }
async function dropTask (columnKey) { if (!props.admin || !draggedTask.value || draggedTask.value.columnKey === columnKey) return; const task = draggedTask.value; draggedTask.value = null; await moveTask(task, columnKey) }
async function moveTask (task, columnKey) { try { const response = await api.put(`/admin/projects/${props.project._id}/tasks/${task._id}`, { ...task, columnKey, startDate: task.startDate ? String(task.startDate).slice(0, 10) : '', dueDate: task.dueDate ? String(task.dueDate).slice(0, 10) : '' }, { headers }); tasks.value = tasks.value.map((item) => item._id === task._id ? response.data.data : item) } catch (error) { notifyError(error) } }
function removeTask (task) { $q.dialog({ title: 'Excluir tarefa', message: `Remover ${task.title}?`, cancel: true, persistent: true }).onOk(async () => { try { await api.delete(`/admin/projects/${props.project._id}/tasks/${task._id}`, { headers }); tasks.value = tasks.value.filter((item) => item._id !== task._id); $q.notify({ type: 'positive', message: 'Tarefa removida.' }) } catch (error) { notifyError(error) } }) }
function openColumns () { editableColumns.value = board.value.columns.map((column) => ({ ...column })); columnsDialog.value = true }
function addColumn () { const title = newColumnTitle.value.trim(); if (!title) return; editableColumns.value.push({ title, key: `${title.toLowerCase().replace(/[^a-z0-9]+/g, '_')}_${Date.now().toString(36)}`, position: editableColumns.value.length }); newColumnTitle.value = '' }
async function saveColumns () { if (!editableColumns.value.length) return; saving.value = true; try { const response = await api.put(`/admin/projects/${props.project._id}/board/columns`, { columns: editableColumns.value }, { headers }); board.value = response.data.data.board; tasks.value = response.data.data.tasks; columnsDialog.value = false; $q.notify({ type: 'positive', message: 'Colunas atualizadas.' }) } catch (error) { notifyError(error) } finally { saving.value = false } }
function openRequest (task) { requestTask.value = task; requestDescription.value = ''; requestDialog.value = true }
async function requestChange () { saving.value = true; try { await api.post('/tickets', { projectId: props.project._id, taskId: requestTask.value._id, title: `Ajuste na tarefa: ${requestTask.value.title}`, type: 'project', description: requestDescription.value }, { headers }); requestDialog.value = false; $q.notify({ type: 'positive', message: 'Chamado aberto para a equipe.' }) } catch (error) { notifyError(error) } finally { saving.value = false } }
function notifyError (error) { $q.notify({ type: 'negative', message: error.response?.data?.message || 'Nao foi possivel concluir a operacao.' }) }
onMounted(load)
</script>

<style scoped>
.portal-module { display: grid; gap: 1rem; color: #effffb; }.portal-module__head { display: flex; align-items: flex-end; justify-content: space-between; gap: 1rem; }.portal-module__head > div:first-child { display: grid; gap: .25rem; }.portal-module__eyebrow { color: #8fffee; font-size: .66rem; font-weight: 900; letter-spacing: .14em; text-transform: uppercase; }.portal-module h2 { margin: .2rem 0 0; color: #effffb; font-size: clamp(1.5rem, 3vw, 2.5rem); }.portal-module__head p { margin: 0; color: rgba(229,255,250,.62); font-size: .78rem; }.portal-module__primary { color: #03110f; background: linear-gradient(135deg, #8fffee, #13bc9d); font-weight: 800; }.board-module__head-actions { display: flex; gap: .5rem; }.board-module__mobile-controls { display: none; gap: .6rem; }.board-module__columns { display: grid; grid-template-columns: repeat(5, minmax(180px, 1fr)); gap: .65rem; overflow-x: auto; padding-bottom: .5rem; }.board-column { min-height: 360px; padding: .65rem; border: 1px solid rgba(19,188,157,.22); border-radius: .7rem; background: rgba(4,24,25,.72); }.board-column__head { display: flex; align-items: flex-start; justify-content: space-between; gap: .5rem; margin-bottom: .65rem; }.board-column__head > div { display: flex; align-items: center; gap: .4rem; }.board-column__head span { color: #50dcc4; font-size: .6rem; }.board-column__head h3 { margin: 0; font-size: .75rem; }.board-column__head b { color: #8fffee; font-size: .72rem; }.board-column__tasks { display: grid; gap: .55rem; }.board-task { padding: .7rem; border: 1px solid rgba(143,255,238,.14); border-radius: .55rem; background: rgba(7,40,40,.68); cursor: grab; }.board-task:active { cursor: grabbing; }.board-task__meta, .board-task__footer { display: flex; align-items: center; justify-content: space-between; gap: .4rem; }.board-task__meta { color: rgba(229,255,250,.52); font-size: .6rem; }.board-task h4 { margin: .55rem 0 .3rem; font-size: .78rem; line-height: 1.35; }.board-task p { margin: 0; color: rgba(239,255,251,.63); font-size: .67rem; line-height: 1.45; }.board-task__footer { margin-top: .7rem; color: rgba(229,255,250,.45); font-size: .58rem; }.board-task__actions { display: inline-flex; align-items: center; gap: .1rem; }.board-task__actions :deep(.q-btn) { color: #8fffee; font-size: .62rem; }.board-column__empty { padding: 1rem .4rem; color: rgba(229,255,250,.38); font-size: .68rem; text-align: center; }.board-module__loading { display: flex; align-items: center; gap: .7rem; color: rgba(239,255,251,.7); }.portal-module__dialog { width: min(94vw, 620px); color: #effffb; background: #061819; border: 1px solid rgba(19,188,157,.3); }.portal-module__dialog-head { display: flex; align-items: flex-start; justify-content: space-between; gap: .8rem; }.portal-module__dialog h3 { margin: .4rem 0 0; font-size: 1.15rem; }.portal-module__dialog :deep(.q-field__control) { color: #effffb; background: rgba(7,40,40,.74); }.portal-module__dialog :deep(.q-field__native), .portal-module__dialog :deep(.q-field__label) { color: rgba(239,255,251,.8); }.board-module__dates { display: grid; grid-template-columns: 1fr 1fr; gap: .6rem; margin-top: .6rem; }.board-module__column-edit { display: grid; grid-template-columns: 1fr auto; gap: .45rem; margin-bottom: .5rem; }.board-module__column-add { display: grid; grid-template-columns: 1fr auto; gap: .45rem; margin-top: 1rem; }.board-module__request-copy { color: rgba(239,255,251,.72); font-size: .8rem; line-height: 1.5; }.board-module__request-copy strong { color: #8fffee; }@media (max-width: 800px) { .portal-module__head { align-items: flex-start; flex-direction: column; }.board-module__head-actions { width: 100%; }.board-module__head-actions .q-btn { flex: 1; }.board-module__mobile-controls { display: grid; grid-template-columns: 1fr auto; }.board-module__columns { display: block; overflow: visible; }.board-column { display: none; min-height: 280px; }.board-column:not(.board-column--mobile-hidden) { display: block; }.board-module__dates { grid-template-columns: 1fr; }}
</style>
